    gap: 6,
    background: T.teal,
    color: T.white,
    border: 'none',
    borderRadius: 7,
    padding: '7px 12px',
    fontSize: 12,
    fontWeight: 600,
    cursor: 'pointer',
    whiteSpace: 'nowrap'
  },
  searchWrap: {
    display: 'flex',
    alignItems: 'center',
    gap: 7,
    border: `1px solid ${T.border}`,
    borderRadius: 7,
    padding: '6px 10px',
    backgroundColor: T.bg
  },
  searchInput: {
    border: 'none',
    outline: 'none',
    background: 'transparent',
    fontSize: 13,
    color: T.ink,
    width: 260
  },
  tableFooter: {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
    padding: '10px 18px',
    borderTop: `1px solid ${T.border}`,
    backgroundColor: '#fafafa'
  }
